+function makeSessionMemoryConfig(tempDir: string, messages?: number): OpenClawConfig {
+  return {
+    agents: { defaults: { workspace: tempDir } },
+    ...(typeof messages === "number"
+      ? {
+          hooks: {
+            internal: {
+              entries: {
+                "session-memory": { enabled: true, messages },
+              },
+            },
+          },
+        }
+      : {}),
+  } satisfies OpenClawConfig;
+}
